const dealId = $input.first().json.query?.deal_id || '';
if (!dealId) throw new Error('deal_id query parameter is required');
const sq = s => s.replace(/'/g, "''");
return [{
  json: {
    deal_id: dealId,
    health_sql: `SELECT d.deal_id, d.company_name, d.deal_stage, d.deal_value_usd, d.close_date, d.forecast_category, dh.pain_score, dh.power_score, dh.vision_score, dh.value_score, dh.change_score, dh.control_score, dh.p2v2c2_total, dh.critical_activity_stage, dh.trend_direction, dh.score_vs_previous, dh.next_step, dh.next_step_date, dh.pe_sponsor_score, dh.dap_exists, dh.dap_agreed, dh.dap_has_14_day_gap, dh.dap_next_milestone, dh.dap_next_milestone_date, dh.dap_timeline, dh.dap_status, dh.dap_milestones_complete, dh.dap_milestones_total, dh.dap_summary, dh.risks, dh.general_narrative, dh.scored_at FROM deals d LEFT JOIN LATERAL (SELECT * FROM deal_health WHERE deal_id = d.deal_id ORDER BY scored_at DESC LIMIT 1) dh ON true WHERE d.deal_id = '${sq(dealId)}' LIMIT 1`,
    stakeholders_sql: `SELECT DISTINCT ON (name) name, title, email, cps_role, directly_engaged FROM deal_stakeholders WHERE deal_id = '${sq(dealId)}' ORDER BY name, scored_at DESC`,
    outputs_sql: `SELECT id, output_type, status, subject, full_content AS body, recipient_email, recipient_name, sent_at AS created_at FROM outputs_log WHERE deal_id = '${sq(dealId)}' ORDER BY sent_at DESC LIMIT 20`,
    history_sql: `SELECT scored_at::DATE AS score_date, p2v2c2_total FROM deal_health WHERE deal_id = '${sq(dealId)}' AND trigger_type != 'calendar_only' ORDER BY scored_at ASC LIMIT 8`
  }
}];

